insert into public.lesson_versions
  (id, lesson_id, version, title_sv, lead_sv, estimated_minutes, content_blocks, status)
values
  ('51000000-0000-0000-0000-000000000001', '50000000-0000-0000-0000-000000000001', 1, 'Distans och fart till sjöss', 'Varför sjön räknar i nautiska mil och knop — och hur du växlar mellan enheterna utan att tveka.',
   8, '[{"type":"markdown","body_sv":"## Nautisk mil och knop\n\nEn **nautisk mil (M)** är 1 852 meter och motsvarar en latitudminut. En **knop** är en nautisk mil per timme.\n\nAtt enheterna hänger ihop med sjökortets gradnät är ingen slump: det är därför distanser alltid mäts mot latitudskalan i kortets kant."},{"type":"callout","tone":"info","body_sv":"Knop är redan ''per timme''. Att säga ''knop per timme'' är alltså dubbelt — och ett vanligt nybörjarfel."},{"type":"worked_example","body_sv":"**Exempel.** Du läser av 2,5 latitudminuter mellan två punkter.\n\n1. 1 latitudminut = 1 M.\n2. Distansen är alltså 2,5 M.\n3. I meter: 2,5 × 1 852 m = 4 630 m."}]'::jsonb, 'review')
on conflict (lesson_id, version) do nothing;

