insert into public.lesson_versions
  (id, lesson_id, version, title_sv, lead_sv, estimated_minutes, content_blocks, status)
values
  ('51000000-0000-0000-0000-000000000002', '50000000-0000-0000-0000-000000000002', 1, 'Laterala sjömärken', 'Röd eller grön, kon eller cylinder — så väljer du rätt sida varje gång.',
   10, '[{"type":"markdown","body_sv":"## Systemet IALA A\n\nI Sverige gäller IALA-system A. Vid **ingående från sjön** (mot hamn):\n\n- **Babordsmärken** är **röda** med **cylinderformat** topptecken — håll dem om **babord**.\n- **Styrbordsmärken** är **gröna** med **konformat** topptecken (spets upp) — håll dem om **styrbord**."},{"type":"callout","tone":"warning","body_sv":"Riktningen räknas vid ingående från sjön. På väg ut gäller det omvända — kontrollera alltid färdriktningen i förhållande till farleden."},{"type":"markdown","body_sv":"## Ljus i mörker\n\nBabordsmärken lyser rött och styrbordsmärken grönt. Rytmen kan variera, men färgen följer alltid sidan."}]'::jsonb, 'review')
on conflict (lesson_id, version) do nothing;

