values
  ('51000000-0000-0000-0000-000000000003', '50000000-0000-0000-0000-000000000003', 1, 'Fart, tid och distans', 'En formel, tre varianter — grunden för all planering ombord.',
   12, '[{"type":"markdown","body_sv":"## Sambandet\n\n**Distans = fart × tid.** Ur samma samband följer:\n\n- Tid = distans / fart\n- Fart = distans / tid\n\nHåll enheterna rena: distans i nautiska mil, fart i knop, tid i timmar. Minuter räknas om: minuter = timmar × 60."},{"type":"worked_example","body_sv":"**Exempel.** 6,0 M med farten 5,0 knop.\n\n1. Tid = 6,0 / 5,0 = 1,2 timmar.\n2. 1,2 × 60 = **72 minuter**."},{"type":"callout","tone":"info","body_sv":"Snabbkontroll: vid 6 knop går båten 1 M på 10 minuter. Vid 12 knop: 1 M på 5 minuter."}]'::jsonb, 'review')
on conflict (lesson_id, version) do nothing;

