insert into public.lesson_versions
  (id, lesson_id, version, title_sv, lead_sv, estimated_minutes, content_blocks, status)
values
  ('51000000-0000-0000-0000-000000000004', '50000000-0000-0000-0000-000000000004', 1, 'Väjningsreglernas grunder', 'Möte, korsande kurs och upphinnande — de tre situationer du måste kunna i sömnen.',
   14, '[{"type":"markdown","body_sv":"## Tre grundsituationer för maskindrivna fartyg\n\n1. **Möte stäv mot stäv:** båda girar **styrbord** och passerar babord mot babord.\n2. **Korsande kurser:** den som har den andra på sin **styrbordssida** väjer.\n3. **Upphinnande:** den som hinner upp väjer — alltid, oavsett fartygstyp."},{"type":"markdown","body_sv":"## Segel och motor\n\nEtt maskindrivet fartyg väjer normalt för ett segelfartyg. Men ett segelfartyg som går **för motor** räknas som maskindrivet — även med seglen uppe."},{"type":"callout","tone":"warning","body_sv":"En väjning ska vara **tydlig och göras i god tid**. Små, sena kursändringar skapar osäkerhet och farliga situationer."}]'::jsonb, 'review')
on conflict (lesson_id, version) do nothing;

